// monster-guard — admission, capability delegation/revocation, and runtime
// enforcement for Moonshine plugins. Part of the monster family.
//
//   monster-guard delegate <name> <caps> [--ttl <secs>]
//       Mint a "command grant" UCAN (root -> plugin:<name>, caps as constraints)
//       and store it. Run by setup.sh when a plugin is admitted.
//
//   monster-guard run --name <name> --caps <caps> [--lease <secs>] [--max <secs>] [--teleport <file>] -- <cmd> [args...]
//       Verify the command grant (signature + expiry + revocation), mint a short
//       per-invocation lease, then run <cmd> under the macOS sandbox while a
//       supervisor renews the lease and kills the process if it expires, is
//       revoked, or exceeds a hard ceiling.
//
//   monster-guard revoke command <name> | invocation <jti> | token <token>
//       Add to the revocation store. A running invocation is killed at its next
//       renewal tick; future runs are denied.
//
// caps: comma list of fs,net,exec (or '-'). Enforcement (when sandboxable):
//   no net  -> (deny network*)      no fs -> (deny file-write*)   no exec -> (deny process-fork)

use std::process::Command;
use std::time::{Duration, Instant};

mod bowl;
mod lease;
mod oath;
mod qspec;
mod role;
mod store;
mod teleport;

use a0n_auth::ucan::{issue, parse, verify};
use a0n_auth::{Capability, IssueOptions, VerifyOptions};
use lease::{
    spawn_in_process_group, supervise, LeaseAuthority, LeaseConfig, LeaseExit, RenewOutcome,
};

const VALID_CAPS: [&str; 3] = ["fs", "net", "exec"];
const SANDBOX_ACTIVE_ENV: &str = "MONSTER_GUARD_SANDBOX_ACTIVE";
/// Command grants are long-lived admissions, re-minted whenever setup runs.
const DEFAULT_GRANT_TTL_SECS: i64 = 30 * 24 * 60 * 60;
/// Per-invocation lease: short by default, auto-renewed while authorized.
const DEFAULT_LEASE_SECS: i64 = 60;

fn main() {
    let args: Vec<String> = std::env::args().collect();
    match args.get(1).map(String::as_str) {
        Some("delegate") | Some("admit") => cmd_delegate(&args[2..]),
        Some("run") => cmd_run(&args[2..]),
        Some("revoke") => cmd_revoke(&args[2..]),
        Some("qspec") => cmd_qspec(&args[2..]),
        Some("bowl") => cmd_bowl(&args[2..]),
        Some("oath") => cmd_oath(&args[2..]),
        Some("role") => cmd_role(&args[2..]),
        Some("-h") | Some("--help") | None => usage(),
        Some(other) => {
            eprintln!("monster-guard: unknown subcommand '{other}'");
            usage_err();
        }
    }
}

fn usage() {
    println!("monster-guard — admission, delegation, revocation, and lease enforcement");
    println!();
    println!("Usage:");
    println!("  monster-guard delegate <name> <caps> [--ttl <secs>] [--qspec <file>] [--bowl <file>] [--oath <file>]");
    println!("  monster-guard run --name <name> --caps <caps> [--lease <secs>] [--max <secs>] [--teleport <file>] -- <cmd> [args...]");
    println!("  monster-guard revoke command <name> | invocation <jti> | token <token>");
    println!("  monster-guard qspec verify <file>");
    println!("  monster-guard bowl verify <file>");
    println!("  monster-guard oath verify <file>");
    println!("  monster-guard role list");
    println!("  monster-guard role show <role>");
    println!("  monster-guard role grant <agent> <role> [--ws <ws>] [--scope <path>] [--ttl <secs>] [--oath <file>] [--qspec <file>] [--bowl <file>]");
    println!("  monster-guard role check <agent> <can> <resource> [--cmd <command>] [--ws <ws>]");
    println!("  monster-guard role define <role> <file.json> --as <admin>");
    println!("  monster-guard role rm <role> --as <admin>");
    println!();
    println!("caps: comma list of fs,net,exec (or '-')");
    println!("role: a named bundle of vfs capabilities (read/write/exec/net over a path scope).");
    println!("      `role grant` mints a UCAN carrying the whole bundle; `role check` is the");
    println!("      fine-grained VFS gate. The registry lives at $MONSTER_GUARD_HOME/roles/ and");
    println!("      is mutated by `role define`/`role rm`, gated by a `role/admin` grant (--as).");
    println!("qspec: a JSON quality spec proving the thing works; --qspec on delegate");
    println!("       refuses admission unless the spec passes (the probe argmaxes its token).");
    println!("bowl:  a JSON τ-bowl spec proving the model can be JIT-dequantized at coverage q");
    println!("       with a certified ≤(1−q) quality-loss bound (runs bowl-probe on real tiles).");
    println!("       --bowl on delegate refuses admission unless the conformal gate admits.");
    println!("oath:  a sworn conduct commitment; --oath on delegate accepts EITHER a signed");
    println!("       oath-token (a UCAN signed by the swearer; the grant then carries crypto");
    println!("       proof of who swore it — Ulysses when iss==aud) OR raw JSON (unsigned).");
    println!("       Admission refuses unless the swearer signature verifies (for a token),");
    println!("       the requested caps are a subset of the oath, and the ttl is within it,");
    println!("       then binds the verified terms + proof (sworn_by/ulysses/signed) as fct.");
}

fn usage_err() -> ! {
    usage();
    std::process::exit(2);
}

fn parse_caps(s: &str) -> Result<Vec<String>, String> {
    let mut out: Vec<String> = Vec::new();
    for tok in s.split(',') {
        let t = tok.trim();
        if t.is_empty() || t == "-" {
            continue;
        }
        if !VALID_CAPS.contains(&t) {
            return Err(format!("invalid capability '{t}' (expected fs, net, or exec)"));
        }
        if !out.iter().any(|c| c == t) {
            out.push(t.to_string());
        }
    }
    Ok(out)
}

/// The capability a command grant carries / an invocation requires.
fn plugin_capability(name: &str, caps: &[String]) -> Capability {
    Capability {
        can: "exec/run".to_string(),
        with: format!("plugin:{name}"),
        constraints: Some(serde_json::json!({ "caps": caps })),
    }
}

fn fail(msg: impl AsRef<str>) -> ! {
    eprintln!("monster-guard: {}", msg.as_ref());
    std::process::exit(2);
}

// ----------------------------------------------------------------------------
// delegate
// ----------------------------------------------------------------------------

fn cmd_delegate(args: &[String]) {
    if args.len() < 2 {
        fail("usage: monster-guard delegate <name> <caps> [--ttl <secs>] [--qspec <file>] [--oath <file>]");
    }
    let name = &args[0];
    let caps_raw = &args[1];
    if !store::valid_name(name) {
        fail(format!("invalid plugin name '{name}'"));
    }
    let caps = parse_caps(caps_raw).unwrap_or_else(|e| fail(e));
    let mut ttl = DEFAULT_GRANT_TTL_SECS;
    let mut qspec_file: Option<String> = None;
    let mut bowl_file: Option<String> = None;
    let mut oath_file: Option<String> = None;
    let mut i = 2;
    while i < args.len() {
        match args[i].as_str() {
            "--ttl" => {
                i += 1;
                ttl = args
                    .get(i)
                    .and_then(|s| s.parse().ok())
                    .unwrap_or_else(|| fail("--ttl needs an integer"));
            }
            "--qspec" => {
                i += 1;
                qspec_file = Some(
                    args.get(i)
                        .cloned()
                        .unwrap_or_else(|| fail("--qspec needs a file path")),
                );
            }
            "--bowl" => {
                i += 1;
                bowl_file = Some(
                    args.get(i)
                        .cloned()
                        .unwrap_or_else(|| fail("--bowl needs a file path")),
                );
            }
            "--oath" => {
                i += 1;
                oath_file = Some(
                    args.get(i)
                        .cloned()
                        .unwrap_or_else(|| fail("--oath needs a file path")),
                );
            }
            other => fail(format!("delegate: unexpected argument '{other}'")),
        }
        i += 1;
    }

    // Admission gate (quality): a declared quality spec is an acceptance
    // criterion, exactly parallel to capability validation. No proof, no grant —
    // "fake agent" code structurally cannot be admitted. Run this first.
    if let Some(file) = &qspec_file {
        match qspec::verify(file) {
            Ok(()) => {
                println!("monster-guard: quality spec passed ({file})");
            }
            Err(e) => {
                eprintln!("monster-guard: admission denied: quality spec failed");
                eprintln!("  {e}");
                std::process::exit(2);
            }
        }
    }

    // Admission gate (JIT-dequantization / τ-bowl): a bowlspec is the NEW
    // admission dimension — "this model/config can be served at coarse-code
    // (Q4/E8/Leech, masked per-op) cost with a CERTIFIED ≤(1−q) quality-loss
    // bound, distribution-free, no truth at inference". It runs the runtime
    // conformal gate (`bowl-probe` on REAL admitted tiles) and refuses admission
    // unless the gate admits — and, if a floor is declared, unless every
    // coverage q at/above it is certified. Miss-not-lie: it refuses what it
    // cannot bound. Orthogonal to qspec ("right token?") — this is "cheap +
    // certified?". The certified coverage column is printed for the ledger.
    if let Some(file) = &bowl_file {
        match bowl::verify(file) {
            Ok(cert) => {
                let at = cert
                    .certified_at
                    .map(|q| format!("coverage q≥{q}"))
                    .unwrap_or_else(|| "no coverage".to_string());
                println!(
                    "monster-guard: τ-bowl gate passed ({file}) — JIT-dequant certified ({at}); \
                     {}",
                    bowl::fmt_coverage(&cert.coverage)
                );
            }
            Err(e) => {
                eprintln!("monster-guard: admission denied: τ-bowl gate failed");
                eprintln!("  {e}");
                std::process::exit(2);
            }
        }
    }

    // Admission gate (conduct): an oath is a sworn, bounded commitment. The oath
    // may be EITHER a signed oath-token (a UCAN signed by the swearer — the grant
    // then carries cryptographic proof of WHO swore it) OR raw JSON (unsigned,
    // back-compat). A token's swearer signature is verified at admission; the
    // requested caps must be a subset of the verified oath and the ttl within it.
    // On success the VERIFIED terms plus proof metadata (sworn_by / ulysses /
    // signed) are bound into the minted grant as its `fct`, so the grant carries
    // — and is bounded by — the commitment, and records who cryptographically
    // swore it.
    let mut issue_opts = IssueOptions::default();
    if let Some(file) = &oath_file {
        let revocations = store::load_revocations();
        let admitted = oath::load(file, &revocations).unwrap_or_else(|e| {
            eprintln!("monster-guard: admission denied: oath violation: {e}");
            std::process::exit(2);
        });
        match oath::enforce(&admitted, &caps, ttl) {
            Ok(fct) => {
                let how = if admitted.signed {
                    if admitted.ulysses {
                        format!(
                            "Ulysses oath signed by {}",
                            admitted.swearer.as_deref().unwrap_or("?")
                        )
                    } else {
                        format!(
                            "oath signed by {}",
                            admitted.swearer.as_deref().unwrap_or("?")
                        )
                    }
                } else {
                    "unsigned oath".to_string()
                };
                println!("monster-guard: oath sworn and bound ({how}) ({file})");
                issue_opts.facts = Some(fct);
            }
            Err(why) => {
                eprintln!("monster-guard: admission denied: oath violation: {why}");
                std::process::exit(2);
            }
        }
    }

    let root = store::ensure_root().unwrap_or_else(|e| fail(e));
    let cap = plugin_capability(name, &caps);
    let token = issue(&root, root.did(), &[cap], ttl, &issue_opts)
        .unwrap_or_else(|e| fail(e.to_string()));
    store::save_grant(name, &token).unwrap_or_else(|e| fail(e));

    let shown = if caps.is_empty() { "-".into() } else { caps.join(",") };
    println!("monster-guard: delegated exec/run on plugin:{name} caps=[{shown}] (grant ttl {ttl}s)");
}

