fn cmd_qspec(args: &[String]) {
    match args.first().map(String::as_str) {
        Some("verify") => {
            let file = args
                .get(1)
                .unwrap_or_else(|| fail("usage: monster-guard qspec verify <file>"));
            match qspec::verify(file) {
                Ok(()) => {
                    println!("PASS: {file}");
                    std::process::exit(0);
                }
                Err(e) => {
                    println!("FAIL: {file}");
                    eprintln!("{e}");
                    std::process::exit(2);
                }
            }
        }
        Some(other) => fail(format!("unknown qspec subcommand '{other}' (verify)")),
        None => fail("usage: monster-guard qspec verify <file>"),
    }
}

// ----------------------------------------------------------------------------
// bowl (τ-bowl / JIT-dequantization admission)
// ----------------------------------------------------------------------------

fn cmd_bowl(args: &[String]) {
    match args.first().map(String::as_str) {
        Some("verify") => {
            let file = args
                .get(1)
                .unwrap_or_else(|| fail("usage: monster-guard bowl verify <file>"));
            match bowl::verify(file) {
                Ok(cert) => {
                    println!("PASS: {file}");
                    println!("  admitted: {}", cert.admitted);
                    println!("  e8_energy_ge_cubic: {}", cert.e8_energy_ok);
                    match cert.certified_at {
                        Some(q) => println!("  certified_jit_dequant_at: coverage q≥{q}"),
                        None => println!("  certified_jit_dequant_at: (none admitted)"),
                    }
                    println!("  coverage: {}", bowl::fmt_coverage(&cert.coverage));
                    std::process::exit(0);
                }
                Err(e) => {
                    println!("FAIL: {file}");
                    eprintln!("{e}");
                    std::process::exit(2);
                }
            }
        }
        Some(other) => fail(format!("unknown bowl subcommand '{other}' (verify)")),
        None => fail("usage: monster-guard bowl verify <file>"),
    }
}

// ----------------------------------------------------------------------------
// oath
// ----------------------------------------------------------------------------

fn cmd_oath(args: &[String]) {
    match args.first().map(String::as_str) {
        Some("verify") => {
            let file = args
                .get(1)
                .unwrap_or_else(|| fail("usage: monster-guard oath verify <file>"));
            // For a signed oath-token this verifies the swearer's signature (DENY
            // on invalid/expired/revoked); for raw JSON it validates structure.
            // The caps/ttl bound checks need a request and so cannot apply to a
            // file in isolation. Report signed-vs-unsigned, the swearer DID, the
            // Ulysses flag, and the terms.
            let revocations = store::load_revocations();
            match oath::verify(file, &revocations) {
                Ok(admitted) => {
                    println!("PASS: {file}");
                    println!("  signed: {}", admitted.signed);
                    if admitted.signed {
                        println!(
                            "  swearer: {}",
                            admitted.swearer.as_deref().unwrap_or("(unknown)")
                        );
                        println!("  ulysses: {}", admitted.ulysses);
                    }
                    println!("  oath: {}", admitted.spec.oath);
                    println!("  max_caps: [{}]", admitted.spec.max_caps.join(","));
                    if let Some(ttl) = admitted.spec.ttl_max_secs {
                        println!("  ttl_max_secs: {ttl}");
                    }
                    std::process::exit(0);
                }
                Err(e) => {
                    println!("FAIL: {file}");
                    eprintln!("{e}");
                    std::process::exit(2);
                }
            }
        }
        Some(other) => fail(format!("unknown oath subcommand '{other}' (verify)")),
        None => fail("usage: monster-guard oath verify <file>"),
    }
}

