fn cmd_role(args: &[String]) {
    match args.first().map(String::as_str) {
        Some("list") => role_list(),
        Some("show") => role_show(&args[1..]),
        Some("grant") => role_grant(&args[1..]),
        Some("check") => role_check(&args[1..]),
        Some("define") => role_define(&args[1..]),
        Some("rm") | Some("delete") => role_rm(&args[1..]),
        Some(other) => fail(format!(
            "unknown role subcommand '{other}' (list|show|grant|check|define|rm)"
        )),
        None => fail("usage: monster-guard role <list|show|grant|check|define|rm> ..."),
    }
}

fn role_list() {
    let reg = role::load_registry();
    println!("monster-guard roles ({} available):", reg.len());
    for spec in reg.values() {
        println!("  {}", spec.summary());
    }
}

fn role_show(args: &[String]) {
    let name = args
        .first()
        .unwrap_or_else(|| fail("usage: monster-guard role show <role>"));
    match role::get_role(name) {
        Some(spec) => {
            let json = serde_json::to_string_pretty(&spec).unwrap_or_else(|e| fail(e.to_string()));
            println!("{json}");
        }
        None => fail(format!("no such role '{name}' (try `role list`)")),
    }
}

/// Shallow-merge `extra`'s object fields into `base` without clobbering existing
/// keys (role metadata wins over oath metadata on a key clash).
fn merge_facts(base: &mut serde_json::Value, extra: serde_json::Value) {
    if let (serde_json::Value::Object(b), serde_json::Value::Object(e)) = (base, extra) {
        for (k, v) in e {
            b.entry(k).or_insert(v);
        }
    }
}

fn role_grant(args: &[String]) {
    if args.len() < 2 {
        fail("usage: monster-guard role grant <agent> <role> [--ws <ws>] [--scope <path>] [--ttl <secs>] [--oath <file>] [--qspec <file>] [--bowl <file>]");
    }
    let agent = &args[0];
    let role_name = &args[1];
    if !store::valid_name(agent) {
        fail(format!("invalid agent name '{agent}'"));
    }
    let mut ws = role::DEFAULT_WORKSPACE.to_string();
    let mut scope: Option<String> = None;
    let mut ttl: Option<i64> = None;
    let mut oath_file: Option<String> = None;
    let mut qspec_file: Option<String> = None;
    let mut bowl_file: Option<String> = None;
    let mut i = 2;
    while i < args.len() {
        match args[i].as_str() {
            "--ws" => {
                i += 1;
                ws = args.get(i).cloned().unwrap_or_else(|| fail("--ws needs a value"));
            }
            "--scope" => {
                i += 1;
                scope = Some(args.get(i).cloned().unwrap_or_else(|| fail("--scope needs a value")));
            }
            "--ttl" => {
                i += 1;
                ttl = Some(
                    args.get(i)
                        .and_then(|s| s.parse().ok())
                        .unwrap_or_else(|| fail("--ttl needs an integer")),
                );
            }
            "--oath" => {
                i += 1;
                oath_file =
                    Some(args.get(i).cloned().unwrap_or_else(|| fail("--oath needs a file path")));
            }
            "--qspec" => {
                i += 1;
                qspec_file =
                    Some(args.get(i).cloned().unwrap_or_else(|| fail("--qspec needs a file path")));
            }
            "--bowl" => {
                i += 1;
                bowl_file =
                    Some(args.get(i).cloned().unwrap_or_else(|| fail("--bowl needs a file path")));
            }
            other => fail(format!("role grant: unexpected argument '{other}'")),
        }
        i += 1;
    }

    let spec = role::get_role(role_name)
        .unwrap_or_else(|| fail(format!("no such role '{role_name}' (try `role list`)")));

    // Resolve the bundle (this validates the role's scope requirements).
    let ctx = role::ResolveCtx {
        workspace: &ws,
        scope: scope.as_deref(),
    };
    let caps = spec.resolve(&ctx).unwrap_or_else(|e| fail(e));
    let coarse = role::coarse_caps_from(&caps);

    // TTL: requested (or default), capped by the role's ceiling.
    let requested_ttl = ttl.unwrap_or(DEFAULT_GRANT_TTL_SECS);
    let ttl = match spec.ttl_max_secs {
        Some(max) if requested_ttl > max => {
            eprintln!(
                "monster-guard: ttl {requested_ttl}s exceeds role '{role_name}' ceiling {max}s; capping to {max}s"
            );
            max
        }
        _ => requested_ttl,
    };

    // Optional admission gates (parallel to `delegate`).
    if let Some(file) = &qspec_file {
        if let Err(e) = qspec::verify(file) {
            eprintln!("monster-guard: admission denied: quality spec failed\n  {e}");
            std::process::exit(2);
        }
        println!("monster-guard: quality spec passed ({file})");
    }
    if let Some(file) = &bowl_file {
        match bowl::verify(file) {
            Ok(_) => println!("monster-guard: τ-bowl gate passed ({file})"),
            Err(e) => {
                eprintln!("monster-guard: admission denied: τ-bowl gate failed\n  {e}");
                std::process::exit(2);
            }
        }
    }

    // Build the grant fact: role metadata, plus a verified oath if supplied.
    let mut fct = role::grant_facts(role_name, &ws, scope.as_deref(), &coarse, caps.len());
    if let Some(file) = &oath_file {
        let revocations = store::load_revocations();
        let admitted = oath::load(file, &revocations).unwrap_or_else(|e| {
            eprintln!("monster-guard: admission denied: oath violation: {e}");
            std::process::exit(2);
        });
        match oath::enforce(&admitted, &coarse, ttl) {
            Ok(oath_fct) => {
                merge_facts(&mut fct, oath_fct);
                println!("monster-guard: oath sworn and bound ({file})");
            }
            Err(why) => {
                eprintln!("monster-guard: admission denied: oath violation: {why}");
                std::process::exit(2);
            }
        }
    }

    let root = store::ensure_root().unwrap_or_else(|e| fail(e));
    let opts = IssueOptions {
        facts: Some(fct),
        ..Default::default()
    };
    let token = issue(&root, root.did(), &caps, ttl, &opts).unwrap_or_else(|e| fail(e.to_string()));
    store::save_grant(agent, &token).unwrap_or_else(|e| fail(e));

    let scope_show = scope.as_deref().unwrap_or("(tree)");
    let coarse_show = if coarse.is_empty() {
        "-".to_string()
    } else {
        coarse.join(",")
    };
    println!(
        "monster-guard: granted role '{role_name}' to '{agent}' on ws '{ws}' scope '{scope_show}' \
         (caps=[{coarse_show}], {} abilities, ttl {ttl}s)",
        caps.len()
    );
}

fn role_check(args: &[String]) {
    if args.len() < 3 {
        fail("usage: monster-guard role check <agent> <can> <resource> [--cmd <command>] [--ws <ws>]");
    }
    let agent = &args[0];
    let can = &args[1];
    let mut resource = args[2].clone();
    let mut cmd: Option<String> = None;
    let mut ws = role::DEFAULT_WORKSPACE.to_string();
    let mut i = 3;
    while i < args.len() {
        match args[i].as_str() {
            "--cmd" => {
                i += 1;
                cmd = Some(args.get(i).cloned().unwrap_or_else(|| fail("--cmd needs a value")));
            }
            "--ws" => {
                i += 1;
                ws = args.get(i).cloned().unwrap_or_else(|| fail("--ws needs a value"));
            }
            other => fail(format!("role check: unexpected argument '{other}'")),
        }
        i += 1;
    }
    // Ergonomics: a bare path is interpreted as a resource under the workspace.
    if !resource.starts_with("vfs:") && !resource.starts_with("policy:") {
        resource = format!("{}:{}:{}", role::VFS_PREFIX, ws, resource);
    }
    match role::check_request(agent, can, &resource, cmd.as_deref()) {
        Ok(()) => {
            let suffix = cmd
                .as_deref()
                .map(|c| format!(" (cmd '{c}')"))
                .unwrap_or_default();
            println!("ALLOW: '{agent}' may '{can}' on '{resource}'{suffix}");
            std::process::exit(0);
        }
        Err(e) => {
            println!("{e}");
            std::process::exit(2);
        }
    }
}

/// Split `args` into positionals and an optional `--as <admin>` flag.
fn split_admin_args(verb: &str, args: &[String]) -> (Vec<String>, Option<String>) {
    let mut positional: Vec<String> = Vec::new();
    let mut admin: Option<String> = None;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--as" => {
                i += 1;
                admin =
                    Some(args.get(i).cloned().unwrap_or_else(|| {
                        fail(format!("{verb}: --as needs an admin agent name"))
                    }));
            }
            other if other.starts_with("--") => fail(format!("{verb}: unexpected flag '{other}'")),
            _ => positional.push(args[i].clone()),
        }
        i += 1;
    }
    (positional, admin)
}

fn role_define(args: &[String]) {
    let (positional, admin) = split_admin_args("role define", args);
    if positional.len() < 2 {
        fail("usage: monster-guard role define <role> <file.json> --as <admin>");
    }
    let role_name = &positional[0];
    let file = &positional[1];
    let admin =
        admin.unwrap_or_else(|| fail("role define requires --as <admin> (a role/admin grant)"));

    // Self-hosting policy: only a role/admin grant may mutate the registry.
    role::require_admin(&admin).unwrap_or_else(|e| {
        eprintln!("monster-guard: admission denied: {e}");
        std::process::exit(2);
    });

    let text = std::fs::read_to_string(file)
        .unwrap_or_else(|e| fail(format!("could not read '{file}': {e}")));
    let mut spec: role::RoleSpec =
        serde_json::from_str(&text).unwrap_or_else(|e| fail(format!("invalid role JSON: {e}")));
    // The <role> argument is authoritative for the stored name.
    spec.name = role_name.clone();
    role::save_role(&spec).unwrap_or_else(|e| fail(e));
    println!(
        "monster-guard: role '{role_name}' defined by admin '{admin}' ({} abilities)",
        spec.abilities.len()
    );
}

fn role_rm(args: &[String]) {
    let (positional, admin) = split_admin_args("role rm", args);
    let role_name = match positional.first() {
        Some(s) => s,
        None => fail("usage: monster-guard role rm <role> --as <admin>"),
    };
    let admin = admin.unwrap_or_else(|| fail("role rm requires --as <admin> (a role/admin grant)"));

    role::require_admin(&admin).unwrap_or_else(|e| {
        eprintln!("monster-guard: admission denied: {e}");
        std::process::exit(2);
    });

    match role::delete_role(role_name) {
        Ok(true) => println!(
            "monster-guard: role override '{role_name}' removed by admin '{admin}' (built-in, if any, restored)"
        ),
        Ok(false) => println!(
            "monster-guard: no on-disk override for '{role_name}' (built-ins cannot be removed)"
        ),
        Err(e) => fail(e),
    }
}

// ----------------------------------------------------------------------------
// run
// ----------------------------------------------------------------------------

struct GrantAuthority {
    grant: String,
    invocation_jti: String,
    root_did: String,
    lease: Duration,
}

impl LeaseAuthority for GrantAuthority {
    fn renew(&self) -> RenewOutcome {
        // Re-read the revocation store every tick so `monster-guard revoke`
        // takes effect on already-running invocations.
        let rev = store::load_revocations();
        let opts = VerifyOptions {
            expected_issuer: Some(&self.root_did),
            revocation: Some(&rev),
            ..Default::default()
        };
        if let Err(e) = verify(&self.grant, &opts) {
            return RenewOutcome::Denied(format!("grant: {e}"));
        }
        if rev.jti.contains(&self.invocation_jti) {
            return RenewOutcome::Denied(format!("invocation {} revoked", self.invocation_jti));
        }
        RenewOutcome::Renewed {
            new_deadline: Instant::now() + self.lease,
        }
    }
}

fn cmd_run(args: &[String]) {
    let mut name: Option<String> = None;
    let mut caps_raw: Option<String> = None;
    let mut lease_secs = DEFAULT_LEASE_SECS;
    let mut max_secs: Option<i64> = None;
    let mut teleport_envelope: Option<String> = None;
    let mut cmd: Vec<String> = Vec::new();
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--name" => { i += 1; name = args.get(i).cloned(); }
            "--caps" => { i += 1; caps_raw = args.get(i).cloned(); }
            "--lease" => { i += 1; lease_secs = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(DEFAULT_LEASE_SECS); }
            "--max" => { i += 1; max_secs = args.get(i).and_then(|s| s.parse().ok()); }
            "--teleport" => { i += 1; teleport_envelope = args.get(i).cloned(); }
            "--" => { cmd = args[i + 1..].to_vec(); break; }
            other => fail(format!("unexpected argument '{other}' before '--'")),
        }
        i += 1;
    }

    // First-class cache-key teleport admission (minimal inline check). OPT-IN:
    // only when --teleport <file> carries a protocol69 envelope. Fail-closed on
    // drift (refuse the run). On a valid projection there is no AmplituhedronCache
    // reachable from monster-guard (the frozen-volume cache lives on the
    // fat-station), so this is always a "miss" here: we admit and fall through to
    // the normal sandboxed spawn. See src/teleport.rs for why this is a minimal
    // check and not the shared distributed_inference::teleport primitive.
    if let Some(env_path) = teleport_envelope.as_deref() {
        match teleport::load_and_validate(env_path) {
            Ok(_env) => {
                eprintln!(
                    "monster-guard: teleport projection ADMITTED (66 xor 7 = 69); \
                     no local frozen-volume cache (miss) -> sandboxed spawn"
                );
            }
            Err(e) => fail(format!("teleport admission denied: {e}")),
        }
    }
    let name = name.unwrap_or_else(|| fail("run: --name <plugin> required"));
    let caps = parse_caps(&caps_raw.unwrap_or_default()).unwrap_or_else(|e| fail(e));
    if cmd.is_empty() {
        fail("run: missing '-- <cmd> [args...]'");
    }
    if !store::valid_name(&name) {
        fail(format!("invalid plugin name '{name}'"));
    }

    let root = store::ensure_root().unwrap_or_else(|e| fail(e));
    let grant = store::load_grant(&name).unwrap_or_else(|| {
        fail(format!("'{name}' is not delegated; run setup.sh, `monster-guard delegate {name} {}`, or `monster-guard role grant {name} <role>`", caps.join(",")))
    });

    let rev = store::load_revocations();

    // A grant minted by `role grant` carries a `role` fact and a vfs/* capability
    // bundle (per-file/dir/tree fs+exec+net), not a single plugin cap. Detect it
    // and verify generically (signature + expiry + revocation), deriving the
    // sandbox caps from the bundle. Plain plugin grants keep the existing path
    // (verify the plugin cap + requested caps, then lease that exact cap).
    let parsed_grant = parse(&grant).ok();
    let is_role_grant = parsed_grant
        .as_ref()
        .and_then(|p| p.payload.fct.as_ref())
        .and_then(|f| f.get("role"))
        .is_some();

    let (caps, invocation) = if is_role_grant {
        let att = parsed_grant
            .as_ref()
            .map(|p| p.payload.att.clone())
            .unwrap_or_default();
        let verify_opts = VerifyOptions {
            expected_issuer: Some(root.did()),
            revocation: Some(&rev),
            ..Default::default()
        };
        if let Err(e) = verify(&grant, &verify_opts) {
            fail(format!("admission denied for role grant '{name}': {e}"));
        }
        // Sandbox caps are the union of the bundle's coarse fs/net/exec caps.
        let derived = role::coarse_caps_from(&att);
        // The per-invocation lease re-delegates the whole bundle to self.
        let invocation = a0n_auth::delegate(&grant, &root, root.did(), &att, lease_secs)
            .unwrap_or_else(|e| fail(format!("could not mint invocation lease: {e}")));
        (derived, invocation)
    } else {
        // Admission: verify the command grant against signature, expiry,
        // revocation, and that it actually grants the requested caps.
        let required = plugin_capability(&name, &caps);
        let verify_opts = VerifyOptions {
            expected_issuer: Some(root.did()),
            required_capabilities: vec![required.clone()],
            revocation: Some(&rev),
            ..Default::default()
        };
        if let Err(e) = verify(&grant, &verify_opts) {
            fail(format!("admission denied for '{name}': {e}"));
        }
        // Mint a short-lived per-invocation lease token (child of the grant).
        let invocation = a0n_auth::delegate(&grant, &root, root.did(), &[required], lease_secs)
            .unwrap_or_else(|e| fail(format!("could not mint invocation lease: {e}")));
        (caps, invocation)
    };
    let invocation_jti = parse(&invocation)
        .ok()
        .and_then(|p| p.payload.jti)
        .unwrap_or_default();

    // Build the sandbox command (or run unsandboxed for unsigned binaries,
    // where macOS refuses to apply a profile — lease + revocation still apply).
    let target = cmd[0].clone();
    let profile = build_profile(&caps);
    let mut command = if sandbox_already_active() {
        eprintln!(
            "monster-guard: inherited active macOS sandbox; running '{target}' without nested sandbox-exec \
             (lease + revocation still enforced)"
        );
        let mut c = Command::new(&cmd[0]);
        c.args(&cmd[1..]);
        c
    } else if is_sandboxable(&target) {
        let mut c = Command::new("/usr/bin/sandbox-exec");
        c.arg("-p").arg(&profile);
        c.args(&cmd);
        c.env(SANDBOX_ACTIVE_ENV, "1");
        c
    } else {
        eprintln!(
            "monster-guard: '{target}' is unsigned; running WITHOUT the macOS sandbox \
             (lease + revocation still enforced)"
        );
        let mut c = Command::new(&cmd[0]);
        c.args(&cmd[1..]);
        c
    };
    spawn_in_process_group(&mut command);
    let child = command.spawn().unwrap_or_else(|e| fail(format!("failed to launch '{target}': {e}")));

    let authority = GrantAuthority {
        grant,
        invocation_jti,
        root_did: root.did().to_string(),
        lease: Duration::from_secs(lease_secs.max(1) as u64),
    };
    let cfg = LeaseConfig {
        ttl: Duration::from_secs(lease_secs.max(1) as u64),
        renew_at: Duration::from_secs((lease_secs.max(2) / 2) as u64),
        hard_ceiling: max_secs.map(|s| Duration::from_secs(s.max(0) as u64)),
        poll: Duration::from_millis(250),
        kill_grace: Duration::from_secs(2),
    };

    match supervise(child, &authority, &cfg) {
        Ok(LeaseExit::Exited(code)) => std::process::exit(code),
        Ok(LeaseExit::KilledExpired) => {
            eprintln!("monster-guard: lease expired without renewal; '{name}' killed");
            std::process::exit(124);
        }
        Ok(LeaseExit::KilledRevoked(reason)) => {
            eprintln!("monster-guard: capability revoked ({reason}); '{name}' killed");
            std::process::exit(125);
        }
        Ok(LeaseExit::KilledCeiling) => {
            eprintln!("monster-guard: hard ceiling reached; '{name}' killed");
            std::process::exit(124);
        }
        Err(e) => fail(format!("supervisor error: {e}")),
    }
}

// ----------------------------------------------------------------------------
// revoke
// ----------------------------------------------------------------------------

fn cmd_revoke(args: &[String]) {
    if args.len() < 2 {
        fail("usage: monster-guard revoke command <name> | invocation <jti> | token <token>");
    }
    let mut rev = store::load_revocations();
    match args[0].as_str() {
        "command" => {
            let name = &args[1];
            if !store::valid_name(name) {
                fail(format!("invalid plugin name '{name}'"));
            }
            match store::load_grant(name) {
                Some(grant) => {
                    rev.revoke_token(&grant);
                    if let Ok(p) = parse(&grant) {
                        if let Some(jti) = p.payload.jti {
                            rev.revoke_jti(jti);
                        }
                    }
                    println!("monster-guard: revoked command '{name}' (running invocations die at next lease tick)");
                }
                None => fail(format!("no grant found for '{name}'")),
            }
        }
        "invocation" => {
            rev.revoke_jti(args[1].clone());
            println!("monster-guard: revoked invocation '{}'", args[1]);
        }
        "token" => {
            rev.revoke_token(&args[1]);
            println!("monster-guard: revoked token");
        }
        other => fail(format!("unknown revoke target '{other}' (command|invocation|token)")),
    }
    store::save_revocations(&rev).unwrap_or_else(|e| fail(e));
}

// ----------------------------------------------------------------------------
// sandbox profile + signing predicate (macOS)
// ----------------------------------------------------------------------------

fn build_profile(caps: &[String]) -> String {
    let has = |c: &str| caps.iter().any(|x| x == c);
    let mut p = String::from("(version 1)(allow default)");
    if !has("net") {
        p.push_str("(deny network*)");
    }
    if !has("fs") {
        p.push_str("(deny file-write*)");
    }
    if !has("exec") {
        p.push_str("(deny process-fork)");
    }
    p
}

fn sandbox_already_active() -> bool {
    std::env::var(SANDBOX_ACTIVE_ENV)
        .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
        .unwrap_or(false)
}

/// macOS only sandboxes validly-signed binaries; `codesign --verify` predicts
/// this exactly (signed binaries + system interpreters pass, unsigned fail).
fn is_sandboxable(target: &str) -> bool {
    Command::new("/usr/bin/codesign")
        .args(["--verify", "--strict", target])
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .status()
        .map(|s| s.success())
        .unwrap_or(false)
}
